<?php require_once __DIR__.'/../../config/app.php'; requireAuth(); $r=fetchOne('SELECT r.*,e.exam_name,s.full_name,s.student_code,c.name course_name FROM results r JOIN exams e ON e.id=r.exam_id JOIN students s ON s.id=r.student_id LEFT JOIN courses c ON c.id=s.course_id WHERE r.id=?',[(int)($_GET['id']??0)]); if(!$r) exit('Not found'); ?><!doctype html><html><head><meta charset="UTF-8"><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"></head><body class="p-4"><div class="container"><h3>Marksheet</h3><p><strong><?=e($r['full_name'])?></strong> (<?=e($r['student_code'])?>)</p><table class="table table-bordered"><tr><th>Course</th><td><?=e($r['course_name']??'')?></td></tr><tr><th>Exam</th><td><?=e($r['exam_name'])?></td></tr><tr><th>Marks</th><td><?=$r['marks']?></td></tr><tr><th>Percentage</th><td><?=$r['percentage']?>%</td></tr><tr><th>Grade</th><td><?=$r['grade']?></td></tr><tr><th>GPA/CGPA</th><td><?=$r['gpa']?> / <?=$r['cgpa']?></td></tr></table><button onclick="window.print()" class="btn btn-secondary">Print</button></div></body></html>
